# Parse global flags then dispatch.
ARGS=()
while [[ $# -gt 0 ]]; do
  case "$1" in
    --force)
      FORCE_REBUILD=1
      shift
      ;;
    *)
      ARGS+=("$1")
      shift
      ;;
  esac
done
set -- "${ARGS[@]+"${ARGS[@]}"}"

case "${1:-deploy}" in
  sync) cmd_sync ;;
  deploy) cmd_deploy ;;
  prune) cmd_prune ;;
  open-sg) cmd_open_sg ;;
  status) load_state; cmd_status ;;
  worker-logs) cmd_worker_logs "$@" ;;
  *) die "Usage: $0 {sync|deploy|prune|open-sg|status|worker-logs} [--force]" ;;
esac

cmd_worker_logs() {
  load_state
  local tail_n="${2:-100}"
  ssh_cmd "docker logs ${WORKER_CONTAINER} --tail ${tail_n} -f 2>&1"
}

